INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('real-estate-moex-01342', 'real-estate', 'real-estate-moex-105-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '事業不得為聯合行為。但因經濟不景氣，致同一行業之事業難以繼續維持或生產過剩，為有計畫適應需 求而限制價格之共同行為，而有益於整體經濟與公共利益，經申請主管機關許可者，不在此限。主管機 關為許可時，應附多少時間之期限？', '["不得逾1年", "不得逾2年", "不得逾3年", "不得逾5年"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "35ce915fa694", "answer_pdf_sha1": "76d85711060b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01343', 'real-estate', 'real-estate-moex-105-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '有關公平交易法對獨占規範之敘述，下列何者錯誤？', '["獨占係指事業在相關市場處於無競爭狀態，或具有壓倒性地位，可排除競爭之能力者", "二以上事業，實際上不為價格之競爭，而其全體之對外關係，具有在相關市場處於無競爭狀態之情形 者，視為獨占", "二事業全體於相關市場之占有率若未達二分之一者，不列入獨占事業認定範圍", "獨占之事業，不得對商品價格或服務報酬，為不當之決定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "35ce915fa694", "answer_pdf_sha1": "76d85711060b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01344', 'real-estate', 'real-estate-moex-105-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '甲建商為銷售新屋建案，委請廣告代理業者乙為整體廣告行銷，由乙請來知名歌星丙代言房屋銷售。乙 基於甲的指示，請求丙於廣告案中大力推薦該建案房屋地點近臺北市，開車只要15分鐘，每天可在天然 溫泉泡湯，然事實上，甲、乙、丙均明知該建案房屋距離臺北市有相當距離，搭高鐵要30分鐘，且無天 然溫泉。試問甲、乙、丙針對虛偽不實廣告行為，應負何種責任？', '["甲、乙、丙均各自單獨負損害賠償責任", "甲、乙應各自單獨負損害賠償責任，丙僅廣告薦證而無責任", "甲應負損害賠償責任，乙、丙應與廣告主甲負連帶損害賠償責任", "甲應負損害賠償責任，乙應與廣告主甲負連帶損害賠償責任，丙僅廣告薦證而無責任"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "35ce915fa694", "answer_pdf_sha1": "76d85711060b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01345', 'real-estate', 'real-estate-moex-105-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '下列何種情形，係屬於公平交易法所稱之結合？', '["無正當理由，對他事業給予差別待遇之行為", "直接或間接控制他事業之業務經營或人事任免", "具競爭關係之同一產銷階段事業，以契約共同決定商品或服務之價格", "以不正當方法，使他事業不為價格之競爭"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "35ce915fa694", "answer_pdf_sha1": "76d85711060b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01346', 'real-estate', 'real-estate-moex-105-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '公平交易法所規範不動產經紀業者涉及違法聯合行為之態樣，下列何者不屬之？', '["共同決定服務報酬收費標準，或協議限制服務報酬之調整", "協議拒絕其他不動產經紀業者參與聯賣", "共同約束收取斡旋金之票期，致使斡旋金票期趨於一致", "廣告宣稱「連續20年仲介服務第一品牌」，惟無銷售數字或意見調查等客觀數據為基礎，顯有虛偽不 實或引人錯誤者"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "35ce915fa694", "answer_pdf_sha1": "76d85711060b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01347', 'real-estate', 'real-estate-moex-105-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '關於不動產經紀業者之行為，下列何者係法律所允許？', '["於受託房屋之廣告虛增房屋總坪數", "未檢附具公信力之銷售數字、客戶調查等客觀數據，即於廣告上宣稱每年委託成交案量為全國第一", "為招攬客戶，推出委託成交之抽獎活動，頭獎為價值15000元之平板電腦一台（名額3名）", "與另一業者共同協議拒絕競爭對手參與聯賣"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "35ce915fa694", "answer_pdf_sha1": "76d85711060b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01348', 'real-estate', 'real-estate-moex-105-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '甲向乙建設公司購買預售屋，雙方以書面訂立買賣定型化契約，關於本契約可能產生法律爭議之敘述， 下列何者錯誤？', '["若契約條款約定買方需繳回契約書，則該條款無效", "若買賣雙方經個別磋商後約定契約審閱期間為20日，但契約定型化條款仍記載「買方享有5日之契約 審閱期間」者，該條款牴觸個別磋商條款之部分為無效", "若賣方乙公司於訂約時，突然口頭告知要求甲應同意：「如買方逾期繳交各期預售屋價金時，即視為 違約，已繳交之價金不予退還」，甲未置可否仍簽下書面契約。由於契約訂立不限於書面要式，雖然 乙之口頭內容未經記載於定型化契約中，但該口頭告知仍構成契約之條款而有效", "若契約條款約定本案預售屋廣告僅供參考，則該條款無效"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "35ce915fa694", "answer_pdf_sha1": "76d85711060b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01349', 'real-estate', 'real-estate-moex-105-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '關於消費爭議調解委員會的敘述，下列何者正確？', '["直轄市、縣（市）政府應設消費爭議調解委員會，置委員5至11名", "調解程序，於直轄市、縣（市）政府或其他適當之處所行之，其程序應公開", "關於消費爭議之調解，當事人不能合意但已甚接近者，調解委員得斟酌一切情形，求兩造利益之平衡，於 不違反兩造當事人之主要意思範圍內，依職權提出解決事件之方案，並送達於當事人", "當事人對於經參與調解委員過半數同意提出解決事件之方案，得於送達後20日之不變期間內，提出異議"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "35ce915fa694", "answer_pdf_sha1": "76d85711060b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01350', 'real-estate', 'real-estate-moex-105-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '依消費者保護法規定，企業經營者與消費者分期付款買賣契約的敘述，下列何者正確？', '["分期付款買賣契約，應以書面載明頭期款、各期價款與其他附加費用", "分期付款買賣契約，未載明利率者，其利率按現金交易價格週年利率百分之六計算之", "分期付款買賣契約，未載明相關應付款項者，消費者不負現金交易價格加計法定利息以外價款之給付義務", "分期付款買賣契約，於消費者要求時，企業經營者應以書面載明消費者應付總價款與現金交易價格之差額"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "35ce915fa694", "answer_pdf_sha1": "76d85711060b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01351', 'real-estate', 'real-estate-moex-105-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '未經消費者要約而對之郵寄或投遞之商品，寄送人未經消費者通知取回，在寄送後逾多少時間未經消費 者表示承諾，而仍不取回其商品者，視為拋棄其寄投之商品：', '["逾1個月", "逾2個月", "逾3個月", "逾6個月"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "35ce915fa694", "answer_pdf_sha1": "76d85711060b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
